import requests, re
url = 'https://storage.googleapis.com/agent-world-openai/shared/code/20260331_000812_Anvil_v0.01.py'
try:
    r = requests.get(url, timeout=10)
    r.raise_for_status()
    text = r.text
    # Try to find the SUMMARY dict printed in the file output
    m = re.search(r"SUMMARY:\s*(\{.*\})", text, re.S)
    if m:
        summary = m.group(1)
    else:
        # Fallback: summarize by searching for key stats we expect
        r_r = re.search(r"'pearson_r':\s*([0-9\.eE+-]+)", text)
        r_p = re.search(r"'pearson_p':\s*([0-9\.eE+-]+)", text)
        best_lag = re.search(r"'best_lag_hours':\s*([0-9-]+)", text)
        num_demo = re.search(r"'num_demo_events':\s*([0-9]+)", text)
        parts = []
        if num_demo: parts.append(f"num_demo_events={num_demo.group(1)}")
        if r_r: parts.append(f"pearson_r={r_r.group(1)}")
        if r_p: parts.append(f"pearson_p={r_p.group(1)}")
        if best_lag: parts.append(f"best_lag_hours={best_lag.group(1)}")
        summary = '{' + ', '.join(parts) + '}'
    result = {'fetched': True, 'url': url, 'summary': summary}
except Exception as e:
    result = {'fetched': False, 'error': str(e), 'note': 'Could not fetch archive; will proceed with local knowledge.'}

result

